{
  "name": "hisse",
  "version": "0.0.1",
  "private": true,
  "packageManager": "npm@10.9.2",
  "workspaces": [
    "packages/*",
    "adapters/*",
    "clients/*"
  ],
  "scripts": {
    "build": "turbo run build",
    "dev": "turbo run dev",
    "test": "turbo run test",
    "format": "prettier --write .",
    "format:check": "prettier --check ."
  },
  "devDependencies": {
    "prettier": "^3.8.1",
    "turbo": "^2.5.4",
    "typescript": "^5.9.3"
  }
}

{
  "name": "@hisse/runtime",
  "version": "0.0.1",
  "private": true,
  "type": "module",
  "main": "dist/index.js",
  "types": "dist/index.d.ts",
  "files": [
    "dist"
  ],
  "dependencies": {
    "@mariozechner/pi-coding-agent": "^0.62.0"
  },
  "scripts": {
    "build": "tsc -p tsconfig.json",
    "test": "echo \"no tests yet\""
  },
  "devDependencies": {
    "typebox": "^1.1.6"
  }
}

{
  "name": "@hisse/connectors",
  "version": "0.0.1",
  "private": true,
  "type": "module",
  "main": "dist/index.js",
  "types": "dist/index.d.ts",
  "files": [
    "dist"
  ],
  "scripts": {
    "build": "tsc -p tsconfig.json",
    "test": "echo \"no tests yet\""
  }
}

{
  "name": "hisse-api",
  "version": "0.0.1",
  "private": true,
  "type": "module",
  "scripts": {
    "dev": "tsx watch src/index.ts",
    "build": "tsc -p tsconfig.json",
    "start": "node dist/src/index.js"
  },
  "dependencies": {
    "@fastify/cors": "^11.1.0",
    "@hisse/connectors": "*",
    "@hisse/runtime": "*",
    "fastify": "^5.6.1"
  },
  "devDependencies": {
    "@types/node": "^24.5.2",
    "tsx": "^4.20.5",
    "typescript": "^5.9.3"
  }
}

